package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetAllowMissingColumnNames_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        boolean value = format.getAllowMissingColumnNames();
        assertFalse(value);
    }

    @Test
    public void testGetAllowMissingColumnNames_WithAllowMissingColumnNames() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(true);
        boolean value = format.getAllowMissingColumnNames();
        assertTrue(value);
    }

    @Test
    public void testGetAllowMissingColumnNames_WithAllowMissingColumnNamesFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(false);
        boolean value = format.getAllowMissingColumnNames();
        assertFalse(value);
    }

    @Test
    public void testGetAllowMissingColumnNames_WithAllowMissingColumnNamesTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(true);
        boolean value = format.getAllowMissingColumnNames();
        assertTrue(value);
    }

    @Test
    public void testGetAllowMissingColumnNames_ExcelConstant() {
        boolean value = CSVFormat.EXCEL.getAllowMissingColumnNames();
        assertTrue(value);
    }
}
